<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script>
function arError(m){$('.isi_warning_delete').text(m||'Attendance Report gagal diproses.');$('.error_data_delete').fadeIn();}
function arFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),employee_id:$('#filter_employee_id').val(),department_code:$('#filter_department_code').val(),shift_id:$('#filter_shift_id').val(),work_location_id:$('#filter_work_location_id').val(),attendance_type:$('#filter_attendance_type').val(),attendance_status:$('#filter_attendance_status').val(),attendance_source:$('#filter_attendance_source').val(),exception_type:$('#filter_exception_type').val(),keyword:$('#filter_keyword').val()};}
function ajaxSel(s,act,ph){$(s).select2({width:'100%',allowClear:true,placeholder:ph,ajax:{url:'<?=base_admin();?>modul/attendance_report/attendance_report_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
$(function(){if($.fn.datepicker){$('.ar-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_attendance_type,#filter_attendance_status,#filter_attendance_source,#filter_exception_type').select2({width:'100%',allowClear:true});ajaxSel('#filter_employee_id','employee_search','Semua Employee');ajaxSel('#filter_department_code','department_search','Semua Department');ajaxSel('#filter_shift_id','shift_search','Semua Shift');ajaxSel('#filter_work_location_id','work_location_search','Semua Work Location');}
var dt=$('#dtb_attendance_report').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'72px',targets:1}],ajax:{url:'<?=base_admin();?>modul/attendance_report/attendance_report_data.php',type:'post',data:function(d){$.extend(d,arFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_posted').text(k.posted||0);$('#kpi_late').text(k.late||0);$('#kpi_absence').text(k.absence||0);$('#kpi_overtime').text(k.overtime||0);$('#kpi_compliance').text((k.compliance||0)+'%');return j.data||[];},error:function(xhr){console.log(xhr.responseText);arError('Data Attendance Report gagal dimuat.');}}});
$('#btn_filter_ar').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_ar').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_employee_id,#filter_department_code,#filter_shift_id,#filter_work_location_id,#filter_attendance_type,#filter_attendance_status,#filter_attendance_source,#filter_exception_type').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_ar').click(function(){window.location='<?=base_admin();?>modul/attendance_report/attendance_report_action.php?act=export&'+$.param(arFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$(document).on('click','.btn-ar-detail',function(){$.post('<?=base_admin();?>modul/attendance_report/attendance_report_action.php?act=detail',{id:$(this).data('id')},function(h){$('#ar_detail_body').html(h);$('#modal_ar_detail').modal('show');});});
});
</script>
